public class CustomMapSerializer extends StdSerializer<EnumMap<?, ?>> {

    private static final long serialVersionUID = 1L;

    public CustomMapSerializer() {
        super(EnumMap.class);
    }

    @Override
    public void serialize(EnumMap<?, ?> map, JsonGenerator gen, SerializerProvider provider) throws IOException {

        gen.writeStartObject();
        Set<Entry<?, ?>> set = map.entrySet();
        Iterator<Entry<?, ?>> iter = set.iterator();

        while (iter.hasNext()) {

            Entry<?, ?> entry = iter.next();
            Object key = entry.getKey();
            if (!key.getClass().isEnum()) {
                continue;
            }

            Enum<?> e = (Enum<?>) key;
            String jsonName = e.getDeclaringClass().getAnnotation(JsonProperty.class) != null ?
                    e.getDeclaringClass().getAnnotation(JsonProperty.class).value() :
                    e.name();

            provider.defaultSerializeField(jsonName, entry.getValue(), gen);
        }
        gen.writeEndObject();
    }
}

